mapper.select:
SELECT 
FROM tb_activity_upgrade_target t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.activity_id = #{activityId}


    AND t.source_type = #{sourceType}


    AND t.baseline_code = #{baselineCode}


    AND t.vehicle_node_code = #{vehicleNodeCode}


    AND t.part_code = #{partCode}


    AND t.software_build_version_id = #{softwareBuildVersionId}


    AND t.critical = #{critical}


    AND t.ota = #{ota}


    AND t.install_seq = #{installSeq}


    AND t.parallel_group = #{parallelGroup}


    AND t.group_no = #{groupNo}


    AND t.force_upgrade = #{forceUpgrade}


    AND t.description = #{description}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.install_seq ASC, t.id ASC

